SELECT COUNT(*) AS total_critical_updates, SUM(patch_size) AS total_patch_size
FROM security_updates
WHERE severity = 'Critical' AND product = 'Product 1';

SELECT COUNT(*) AS total_systems_applied
FROM update_logs
WHERE update_id = 1;

SELECT product, severity
FROM security_updates
WHERE severity = 'Critical';

SELECT update_id
FROM update_logs
WHERE status = 'Applied';

SELECT cve_id, severity, impact
FROM security_updates
ORDER BY cvss_base_score DESC;

SELECT COUNT(*) AS applied_update_count
FROM update_logs
WHERE system_name = 'Server1' AND status = 'Applied';

SELECT su.cve_id, p.product_name
FROM security_updates su
INNER JOIN products p ON su.product = p.product_name;
